#nullable enable // autogenerated

using System.Collections.Generic;
using MukioI18n;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Localization;
using MVZ2Logic.Options;
using MVZ2Logic.Saves;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.commandBlockMode)]
    public class CommandBlockModeOptionDropdown : OptionDropdownDefinition
    {
        public CommandBlockModeOptionDropdown(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return Global.Saves.IsCommandBlockUnlocked();
        }
        public override int GetValue(IOptionContext context)
        {
            return Global.Options.GetCommandBlockMode();
        }
        public override void FillItems(IOptionContext context, List<string> items)
        {
            var localization = Global.Localization;
            items.Add(localization.GetTextParticular(LABEL_MANUAL, LogicStrings.CONTEXT_COMMAND_BLOCK_MODE));
            items.Add(localization.GetTextParticular(LABEL_PREVIOUS, LogicStrings.CONTEXT_COMMAND_BLOCK_MODE));
        }
        public override void OnValueChanged(IOptionContext context, int index)
        {
            Global.Options.SetOptionInt(LogicOptionItemID.commandBlockMode, index);
            Global.Options.SaveOptions();
        }
        [TranslateMsg("命令方块模式", LogicStrings.CONTEXT_COMMAND_BLOCK_MODE)]
        public const string LABEL_MANUAL = "手选";
        [TranslateMsg("命令方块模式", LogicStrings.CONTEXT_COMMAND_BLOCK_MODE)]
        public const string LABEL_PREVIOUS = "前位";
    }
}
